// --- Callback Builder ---

// BuildCanonCallbacks allocates a C canon_callbacks_t struct with function pointers
// pointing to //export trampolines that dispatch to the Go interface.
// The returned pointer must be freed with FreeCanonCallbacks when done.
func BuildCanonCallbacks(impl CanonCallbacks) unsafe.Pointer {
	h := cgo.NewHandle(impl)
	cbs := C._bridge_build_canon_callbacks(unsafe.Pointer(h))
	return unsafe.Pointer(cbs)
}

// FreeCanonCallbacks releases the cgo.Handle and frees the C struct.
func FreeCanonCallbacks(ptr unsafe.Pointer) {
	cbs := (*C.canon_callbacks_t)(ptr)
	cgo.Handle(cbs.ctx).Delete()
	C.free(unsafe.Pointer(cbs))
}

// RegisterCanonAPI registers a Go implementation of the canon API with the apiserver registry.
func RegisterCanonAPI(registry *apiserver.Registry, instance string, impl CanonCallbacks) error {
	ptr := BuildCanonCallbacks(impl)
	return registry.Register("canon", 1, instance, ptr)
}

